// FilterItems filters a slice of map[string]interface{} items using a JavaScript condition script.
// The script is evaluated once per item, with the current item exposed as the global variable 'item'.
// The script should evaluate to a truthy or falsy value; items for which the script is truthy are included in the result.
func FilterItems(conditionScript string, items []map[string]interface{}) ([]map[string]interface{}, error) {
	result := make([]map[string]interface{}, 0)

	// Pre-compile the script to catch syntax errors early and improve performance
	script, err := otto.New().Compile("", conditionScript)
	if err != nil {
		return nil, err
	}

	for _, item := range items {
		vm := otto.New()

		// Inject the current item as a global variable named 'item'
		err := vm.Set("item", item)
		if err != nil {
			return nil, err
		}

		// Run the condition script safely with a timeout to prevent infinite loops (DoS)
		boolResult, err := runWithTimeout(vm, script, 100*time.Millisecond)
		if err != nil {
			return nil, err
		}

		if boolResult {
			result = append(result, item)
		}
	}

	return result, nil
}

// runWithTimeout executes the script on the provided Otto VM with a specified timeout.
// This mitigates Denial of Service (DoS) attacks caused by infinite loops or excessively long execution times.
func runWithTimeout(vm *otto.Otto, script *otto.Script, timeout time.Duration) (boolResult bool, err error) {
	defer func() {
		if caught := recover(); caught != nil {
			if caught == ErrExecutionTimeout {
				err = ErrExecutionTimeout
			} else {
				panic(caught) // Repanic if it's an unexpected panic
			}
		}
	}()

	// The buffer prevents the timer from blocking if the execution finishes early
	vm.Interrupt = make(chan func(), 1)

	timer := time.AfterFunc(timeout, func() {
		vm.Interrupt <- func() {
			panic(ErrExecutionTimeout)
		}
	})
	defer timer.Stop()

	value, err := vm.Run(script)
	if err != nil {
		return false, err
	}

	return value.ToBoolean()
}

