// FilterItems filters a slice of maps based on a JavaScript condition script.
// It uses the Otto VM to evaluate the script for each item.
func FilterItems(conditionScript string, items []map[string]interface{}) ([]map[string]interface{}, error) {
	vm := otto.New()

	// Pre-compile the script for better performance during iteration
	script, err := vm.Compile("", conditionScript)
	if err != nil {
		return nil, fmt.Errorf("failed to compile script: %w", err)
	}

	// Initialize an empty slice to hold the filtered results
	// Using make with 0 capacity, it will grow as needed
	filteredItems := make([]map[string]interface{}, 0)

	for _, item := range items {
		// Inject the current item into the JavaScript environment as "item"
		err := vm.Set("item", item)
		if err != nil {
			return nil, fmt.Errorf("failed to set item in VM: %w", err)
		}

		// Execute the pre-compiled script
		value, err := vm.Run(script)
		if err != nil {
			return nil, fmt.Errorf("failed to execute script: %w", err)
		}

		// Convert the result to a boolean (handles truthy/falsy values automatically)
		isTrue, err := value.ToBoolean()
		if err != nil {
			return nil, fmt.Errorf("failed to convert script result to boolean: %w", err)
		}

		// If the script evaluates to true, append the item to our results
		if isTrue {
			filteredItems = append(filteredItems, item)
		}
	}

	return filteredItems, nil
}

func main() {
	// Example usage
	items := []map[string]interface{}{
		{"id": 1, "name": "Alice", "role": "admin", "active": true},
		{"id": 2, "name": "Bob", "role": "user", "active": true},
		{"id": 3, "name": "Charlie", "role": "user", "active": false},
		{"id": 4, "name": "Diana", "role": "admin", "active": false},
	}

	// JavaScript condition: Keep items where role is 'admin' and active is true
	script := `item.role === 'admin' && item.active === true`

	filtered, err := FilterItems(script, items)
	if err != nil {
		fmt.Printf("Error filtering items: %v\n", err)
		return
	}

	fmt.Printf("Original items count: %d\n", len(items))
	fmt.Printf("Filtered items count: %d\n", len(filtered))
	fmt.Println("Filtered Items:")
	for _, item := range filtered {
		fmt.Printf("- %v\n", item)
	}
}

